bool check_zero(const SCICCR_BITS &obj, const std::string &name) {
    bool all_zero = true;

    all_zero &= check_zero(obj.SCICHAR, name + " " + "2:0 Character length control");
    all_zero &= check_zero(obj.ADDRIDLE_MODE, name + " " + "3 ADDR/IDLE Mode control");
    all_zero &= check_zero(obj.LOOPBKENA, name + " " + "4 Loop Back enable");
    all_zero &= check_zero(obj.PARITYENA, name + " " + "5 Parity enable");
    all_zero &= check_zero(obj.PARITY, name + " " + "6 Even or Odd Parity");
    all_zero &= check_zero(obj.STOPBITS, name + " " + "7 Number of Stop Bits");
    all_zero &= check_zero(obj.rsvd1, name + " " + "15:8 Reserved");

    return all_zero;
}

bool check_zero(const SCICCR_REG &obj, const std::string &name) {
    bool all_zero = true;

    all_zero &= check_zero(obj.all, name + " " + "all");
    all_zero &= check_zero(obj.bit, name + " " + "bit");

    return all_zero;
}

bool check_zero(const SCICTL1_BITS &obj, const std::string &name) {
    bool all_zero = true;

    all_zero &= check_zero(obj.RXENA, name + " " + "0 SCI receiver enable");
    all_zero &= check_zero(obj.TXENA, name + " " + "1 SCI transmitter enable");
    all_zero &= check_zero(obj.SLEEP, name + " " + "2 SCI sleep");
    all_zero &= check_zero(obj.TXWAKE, name + " " + "3 Transmitter wakeup method");
    all_zero &= check_zero(obj.rsvd1, name + " " + "4 Reserved");
    all_zero &= check_zero(obj.SWRESET, name + " " + "5 Software reset");
    all_zero &= check_zero(obj.RXERRINTENA, name + " " + "6 Receive error interrupt enable");
    all_zero &= check_zero(obj.rsvd2, name + " " + "15:7 Reserved");

    return all_zero;
}

